<template>
  <div id="app">
    <div class="container-fluid">
      <div class="row">
        <div class="col-md-12 text-center">
          <button class="btn btn-primary" data-toggle="modal" data-target="#timelineModal">Add Timeline</button>
        </div>
      </div>
      <timeline v-for="(t, index, key) in timelines" :key="key" :id="t"></timeline>
    </div>

    <div class="modal fade" id="timelineModal" tabindex="-1" role="dialog" aria-labelledby="myModalLabel">
      <div class="modal-dialog" role="document">
        <div class="modal-content">
          <div class="modal-header">
            <button type="button" class="close" data-dismiss="modal" aria-label="Close"><span aria-hidden="true">&times;</span></button>
            <h4 class="modal-title" id="myModalLabel">Add Timeline</h4>
          </div>
          <div class="modal-body">
            <div class="row">
              <div class="col-md-12">
                <div class="form-group">
                  <label :for="uid">UID</label>
                  <input type="text" class="form-control" placeholder="UID" :value="uid" @input="updateUid">
                </div>
                <div class="form-group">
                  <label :for="table">Open Table</label>
                  <input type="text" class="form-control" placeholder="Open Table" :value="table" @input="updateTable">
                </div>
              </div>
            </div>
          </div>
          <div class="modal-footer">
            <button type="button" class="btn btn-default" data-dismiss="modal">Cancel</button>
            <button type="button" class="btn btn-primary" @click="createTimeline">Add</button>
          </div>
        </div>
      </div>
    </div>
  </div>
</template>

<script>
import Timeline from './components/timeline'
import { mapMutations } from 'vuex'

const jQuery = window.jQuery

export default {
  name: 'app',
  components: {
    Timeline
  },
  computed: {
    table () {
      return this.$store.state.table
    },
    timelines () {
      return this.$store.state.timelines
    },
    uid () {
      return this.$store.state.uid
    }
  },
  data: () => {
    return {
      elem: null
    }
  },
  mounted () {
    // assign element
    this.elem = jQuery(this.$el.children.timelineModal)
  },
  methods: {
    createTimeline () {
      this.addTimeline()
      this.elem.modal('hide')
    },
    updateTable (e) {
      this.$store.commit('updateTable', e.target.value)
    },
    updateUid (e) {
      this.$store.commit('updateUid', e.target.value)
    },
    ...mapMutations([
      'addTimeline',
      'increment'
    ])
  }
}
</script>

<style>
  html, body {
    margin: 0 auto;
    padding: 0;
  }
  #app {
    font-family: 'Avenir', Helvetica, Arial, sans-serif;
    -webkit-font-smoothing: antialiased;
    -moz-osx-font-smoothing: grayscale;
    color: #2c3e50;
    padding-top:20px;
  }
</style>



