<template>
  <div class="row timeline">
    <div class="col-md-4">
      <div class="form-group">
        <label for="uid">User Id</label>
        <input v-model="timeline.uid" class="form-control"/>
      </div>
      <vue-tabs @tab-change="handleTabChange">
        <v-tab title="Timeline">
          <div class="row" v-for="(op, key, index) in timeline.ops" :key="key">
            <div class="col-md-12">
              <component
                :is="getComponentType(op.op)"
                :op="op"
                :id="id"
                @addRule="addRule"
                @remove="remove"
                @removeRule="removeRule">
              </component>  
            </div>
          </div>

          <div class="row" style="text-align:center">
            <button class="btn btn-default" @click="addCompute">Add Compute</button>
            <button class="btn btn-default" @click="addSelect">Add Select</button>
            <button class="btn btn-default" @click="runTimeline">Run Timeline</button>
          </div>
        </v-tab>

        <v-tab title="Json">
          <textarea readonly class="readonly-textarea" v-model="json"></textarea>
        </v-tab>

        <v-tab title="Macro">
          <div class="text-center" v-show="!macro">
            <img src="static/images/loading.gif" alt="loading macro data">
          </div>
          <textarea readonly class="readonly-textarea" v-show="macro" v-model="macro"></textarea>
        </v-tab>
      </vue-tabs>
    </div>
    <div class="col-md-8">
      <div style="padding: 5px;">
        <span class="badge">Total Rows: {{ totalRows }}</span> <span class="badge">Load Time: {{ duration }} ms</span>
      </div>
      <ag-grid-vue style="width: 100%; height: 500px;"
        :gridOptions="gridOptions"
        :columnDefs="gridOptions.columnDefs"
        class="ag-fresh">
      </ag-grid-vue>
    </div>
  </div>
</template>

<script>
// components
import Compute from './timeline-compute'
import OpenTable from './timeline-opentable'
import TimelineSelect from './timeline-select'
import {AgGridVue} from 'ag-grid-vue'
// services
import TimelineService from '../services/timeline-service'

export default {
  name: 'timeline',
  props: ['id'],
  components: {
    AgGridVue,
    Compute,
    OpenTable,
    TimelineSelect
  },
  data: () => {
    return {
      computeAdded: false,
      currentStart: 0,
      gridOptions: {
        rowModelType: 'infinite',
        paginationPageSize: 100,
        maxBlocksInCache: 10,
        maxConcurrentDatasourceRequests: 1,
        datasource: undefined,
        columnDefs: []
      },
      macro: undefined,
      macroLoading: true
    }
  },
  computed: {
    columns () {
      return this.$store.getters[`timelineModule${this.id}/columns`]
    },
    duration () {
      return this.$store.getters[`timelineModule${this.id}/duration`]
    },
    json () {
      return JSON.stringify(this.timeline, null, 2)
    },
    timeline () {
      return this.$store.getters[`timelineModule${this.id}/timeline`]
    },
    totalRows () {
      return this.$store.getters[`timelineModule${this.id}/totalRows`]
    }
  },
  created () {
    this.gridOptions.datasource = this.createDataSource()
  },
  methods: {
    addCompute () {
      this.timeline.add('Compute')
      this.computeAdded = true
    },
    addRule (op) {
      this.timeline.addRule(op)
    },
    addSelect () {
      this.timeline.add('Select')
    },
    getComponentType (opType) {
      return opType === 'Select' ? 'TimelineSelect' : opType
    },
    handleTabChange (tabIndex, newTab, oldTab) {
      if (newTab.title === 'Macro') {
        this.macro = undefined
        this.loadMacro()
      }
    },
    loadMacro () {
      var self = this

      TimelineService.timelineAsMacro(self.timeline).then(res => {
        self.macro = res.data
      })
    },
    remove (op) {
      this.timeline.remove(op)
    },
    removeRule (op, rule) {
      this.timeline.removeRule(op, rule)
    },
    runTimeline () {
      this.currentStart = this.gridOptions.api.getFirstDisplayedRow()
      console.log(this.currentStart)
      this.gridOptions.api.setDatasource(this.createDataSource())
    },
    createDataSource () {
      var self = this
      return {
        getRows: (params) => {
          // clone initial object then add start and end row
          var options = JSON.parse(JSON.stringify(self.timeline))
          Object.assign(options, {
            startRow: params.startRow,
            endRow: params.endRow
          })

          TimelineService.timeline(options).then(res => {
            var grid = TimelineService.transform(res)
            self.gridOptions.columnDefs = grid.columnDefs

            this.$store.commit(`timelineModule${this.id}/updateDuration`, res.data.duration)
            this.$store.commit(`timelineModule${this.id}/updateTotalRows`, res.data.totalRows)
            this.$store.commit(`timelineModule${this.id}/updateColumns`,
              grid.columnDefs.filter((c) => {
                return c.headerName && c.field
              }).map((c) => {
                return { name: c.headerName.replace(/\r?\n|\r/g, ' '), field: c.field }
              }))

            params.successCallback(grid.rowData, res.data.totalRows)

            if (self.computeAdded) {
              self.$nextTick(() => {
                self.gridOptions.api.ensureIndexVisible(self.currentStart, 'top')
                self.gridOptions.api.ensureColumnVisible(grid.columnDefs[grid.columnDefs.length - 1].field)

                self.computeAdded = false
              })
            }
          })
        }
      }
    }
  }
}
</script>

<style scoped>
  .timeline {
    margin-bottom: 30px;
  }
  .tab-container {
    padding-top: 15px;
  }
  .readonly-textarea {
    height: 400px;
    width: 100%;
  }
  .badge {
    background-color: #2c3e50;
    padding: 8px;
  }
</style>



