import Vue from 'vue'
import Vuex from 'vuex'
import module from './defaults/timeline-default-state'

const {state: stateModule, getters, mutations} = module

Vue.use(Vuex)

export const store = new Vuex.Store({
  state: {
    indexer: 1,
    table: 'pub.demo.baseball.batting',
    timelines: [],
    uid: 'oi_jcristini'
  },
  getters: {
    indexer: state => state.indexer,
    table: state => state.table,
    timelines: state => state.timelines,
    uid: state => state.uid
  },
  mutations: {
    increment: state => state.indexer++,
    addTimeline: (state) => {
      state.timelines.push(state.timelines.length + 1)

      store.registerModule(`timelineModule${state.timelines.length}`, {
        state: stateModule,
        getters,
        mutations,
        namespaced: true // making our module reusable
      })
    },
    updateTable: (state, value) => {
      state.table = value
    },
    updateUid: (state, value) => {
      state.uid = value
    }
  }
})



